import { useState, useContext } from 'react';
import { Link } from 'react-router-dom';
import { FaComment, FaHeart, FaRegHeart, FaEllipsisV } from 'react-icons/fa';
import { AuthContext } from '../context/AuthContext';
import formatDate from '../utils/formatDate';
import forumService from '../services/forumService';
import { toast } from 'react-toastify';

const ForumPostCard = ({ post, refreshPosts }) => {
  const { user } = useContext(AuthContext);
  const [showOptions, setShowOptions] = useState(false);
  const [isLiked, setIsLiked] = useState(post.likes?.includes(user?._id));
  const [likesCount, setLikesCount] = useState(post.likes?.length || 0);

  const handleLike = async () => {
    if (!user) {
      toast.error('Please log in to like posts');
      return;
    }

    try {
      const response = await forumService.likePost(post._id);
      setIsLiked(!isLiked);
      setLikesCount(prevCount => isLiked ? prevCount - 1 : prevCount + 1);
    } catch (error) {
      toast.error('Error liking post');
      console.error('Error liking post:', error);
    }
  };

  const handleDelete = async () => {
    if (window.confirm('Are you sure you want to delete this post?')) {
      try {
        await forumService.deletePost(post._id);
        toast.success('Post deleted successfully');
        refreshPosts();
      } catch (error) {
        toast.error('Error deleting post');
        console.error('Error deleting post:', error);
      }
    }
    setShowOptions(false);
  };

  return (
    <div className="bg-white rounded-lg shadow-md p-4 mb-4">
      <div className="flex justify-between items-start mb-2">
        <div className="flex items-center">
          <div className="w-10 h-10 rounded-full bg-green-600 flex items-center justify-center text-white text-lg font-bold mr-3">
            {post.author?.name?.charAt(0) || 'U'}
          </div>
          <div>
            <h3 className="font-semibold">{post.author?.name || 'Unknown User'}</h3>
            <p className="text-gray-500 text-sm">{formatDate(post.createdAt)}</p>
          </div>
        </div>
        
        {user && post.author?._id === user._id && (
          <div className="relative">
            <button 
              onClick={() => setShowOptions(!showOptions)}
              className="text-gray-500 hover:text-gray-700"
            >
              <FaEllipsisV />
            </button>
            
            {showOptions && (
              <div className="absolute right-0 mt-2 w-48 bg-white rounded-md shadow-lg z-10 border border-gray-200">
                <button
                  onClick={handleDelete}
                  className="block w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-gray-100"
                >
                  Delete Post
                </button>
              </div>
            )}
          </div>
        )}
      </div>
      
      <Link to={`/forum/${post._id}`} className="block">
        <h2 className="text-xl font-bold mb-2 hover:text-green-600">{post.title}</h2>
        <p className="text-gray-700 mb-4">
          {post.description.length > 200 
            ? `${post.description.substring(0, 200)}...` 
            : post.description}
        </p>
      </Link>
      
      <div className="flex items-center justify-between pt-2 border-t border-gray-200">
        <button 
          onClick={handleLike} 
          className="flex items-center text-gray-600 hover:text-green-600"
        >
          {isLiked ? (
            <FaHeart className="text-green-600 mr-1" />
          ) : (
            <FaRegHeart className="mr-1" />
          )}
          <span>{likesCount}</span>
        </button>
        
        <Link to={`/forum/${post._id}`} className="flex items-center text-gray-600 hover:text-green-600">
          <FaComment className="mr-1" />
          <span>{post.comments?.length || 0}</span>
        </Link>
      </div>
    </div>
  );
};

export default ForumPostCard;
